import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 🔄 Dr. Flow — PhD in Control Flow & Async Promises (TypeScript)
 * Generated by Sovereign Forge.
 */
export class FlowPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "flow";
        this.name = "Flow";
        this.emoji = "🔄";
        this.role = "PhD Control Flow Architect";
        this.phd_identity = "Control Flow & Async Promises (TypeScript)";
        this.stack = "Bun";
        this.healingPrompt = "Fix the following async/reactive or stream processing issue. Resolve backpressure problems, unhandled promise rejections, and race conditions. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "\\.then\\([^)]*\\)\\.then\\([^)]*\\)\\.then",
                    "issue": "Callback Hell: Cadeia .then().then().then() — use async/await PhD.",
                    "severity": "high"
          },
          {
                    "regex": "if\\s*\\([^)]+\\)\\s*\\{[^}]*if\\s*\\([^)]+\\)\\s*\\{[^}]*if",
                    "issue": "Pirâmide: Aninhamento profundo de ifs — refatore com early returns PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "switch\\s*\\([^)]*\\)\\s*\\{(?:[^}]*case[^}]*){10,}",
                    "issue": "Switch Monolítico: Muitos cases — use padrão Strategy ou Map PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "Promise\\.all\\([^)]*\\.map\\(async",
                    "issue": "Risco de Paralelismo: Promise.all com map assíncrono sem limite de concorrência PhD.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Flow operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Flow, PhD em Control Flow & Async Promises (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
